    public void completed(WorkflowEventArgs _workflowEventArgs)
    {
        next completed(_workflowEventArgs);

        VendTable           vendTable           = vendTable::findRecId(
                                                        _workflowEventArgs.parmWorkflowContext().parmRecId(),true);
        VendOnHoldHistory   vendOnHoldHistory   = VendOnHoldHistory::findLast(vendTable.AccountNum);

        if(vendOnHoldHistory.ReasonCode == PurchParameters::find().UBSCreationReason ||
           vendOnHoldHistory.ReasonCode == PurchParameters::find().UBSUpdateReason)
        {
            ttsbegin;
            vendTable.Blocked = CustVendorBlocked::No;
            vendTable.doUpdate();
            ttscommit;
            vendOnHoldHistory::createHistoryRecord(vendTable.AccountNum, vendTable.Blocked,PurchParameters::find().UBSApproveReason);
        }
    }
